    content_to_files = {}
    for entry in paths:
        parts = entry.split(' ')
        directory = parts[0]
        for f in parts[1:]:
            name = f[:f.index('(')]
            content = f[f.index('(') + 1:f.index(')')]
            full = directory + '/' + name
            content_to_files.setdefault(content, []).append(full)
    expected = set()
    for content, files in content_to_files.items():
        if len(files) >= 2:
            expected.add(frozenset(files))
    seen = set()
    for group in output:
        if len(group) < 2:
            return False
        fs = frozenset(group)
        if len(fs) != len(group):
            return False
        if fs in seen:
            return False
        seen.add(fs)
        if fs not in expected:
            return False
    return seen == expected

