function validate(args, output) {
    const paths = args[0];
    const contentToFiles = {};
    for (const entry of paths) {
        const parts = entry.split(' ');
        const directory = parts[0];
        for (let i = 1; i < parts.length; i++) {
            const f = parts[i];
            const op = f.indexOf('(');
            const cp = f.indexOf(')');
            const name = f.slice(0, op);
            const content = f.slice(op + 1, cp);
            const full = directory + '/' + name;
            (contentToFiles[content] = contentToFiles[content] || []).push(full);
        }
    }
    const expected = new Set();
    const norm = (arr) => arr.slice().sort().join('\u0001');
    for (const content in contentToFiles) {
        const files = contentToFiles[content];
        if (files.length >= 2) expected.add(norm(files));
    }
    const seen = new Set();
    for (const group of output) {
        if (group.length < 2) return false;
        const uniq = new Set(group);
        if (uniq.size !== group.length) return false;
        const key = norm(group);
        if (seen.has(key)) return false;
        if (!expected.has(key)) return false;
        seen.add(key);
    }
    if (seen.size !== expected.size) return false;
    for (const e of expected) if (!seen.has(e)) return false;
    return true;
}

