class Solution:
    def findDuplicate(self, paths):
        from collections import defaultdict
        buckets = defaultdict(list)
        for entry in paths:
            parts = entry.split(' ')
            directory = parts[0]
            for f in parts[1:]:
                op = f.index('(')
                cp = f.index(')')
                name = f[:op]
                content = f[op + 1:cp]
                buckets[content].append(directory + '/' + name)
        result = []
        for content in sorted(buckets):
            files = buckets[content]
            if len(files) >= 2:
                result.append(sorted(files))
        result.sort()
        return result

