var findDuplicate = function(paths) {
    const buckets = {};
    for (const entry of paths) {
        const parts = entry.split(' ');
        const directory = parts[0];
        for (let i = 1; i < parts.length; i++) {
            const f = parts[i];
            const op = f.indexOf('(');
            const cp = f.indexOf(')');
            const name = f.slice(0, op);
            const content = f.slice(op + 1, cp);
            (buckets[content] = buckets[content] || []).push(directory + '/' + name);
        }
    }
    const cmp = (a, b) => {
        const n = Math.min(a.length, b.length);
        for (let i = 0; i < n; i++) if (a[i] !== b[i]) return a[i] < b[i] ? -1 : 1;
        return a.length - b.length;
    };
    const result = [];
    for (const content of Object.keys(buckets).sort()) {
        const files = buckets[content];
        if (files.length >= 2) result.push(files.slice().sort());
    }
    result.sort(cmp);
    return result;
};
